    prop_oneof![
        Just(ActivationMode::Automatic),
        Just(ActivationMode::Manual),
    ]
}

fn arb_disabled_keys() -> impl Strategy<Value = BTreeSet<Key>> {
    prop::collection::vec(arb_key(), 0..3).prop_map(|keys| keys.into_iter().collect())
}

fn arb_props() -> impl Strategy<Value = Props> {
    (
        prop::option::of(prop::option::of(arb_key())),
        prop::option::of(arb_key()),
        arb_orientation(),
        arb_activation_mode(),
        arb_direction(),
        any::<bool>(),
        any::<bool>(),
        any::<bool>(),
        any::<bool>(),
        arb_disabled_keys(),
        any::<bool>(),
    )
        .prop_map(
            |(
                value,
                default_value,
                orientation,
                activation_mode,
                dir,
                loop_focus,
                disallow_empty_selection,
                lazy_mount,
                unmount_on_exit,
                disabled_keys,
                reorderable,
            )| Props {
                id: "tabs".to_string(),
                value,
                default_value,
                orientation,
                activation_mode,
                dir,
                loop_focus,
                disallow_empty_selection,
                lazy_mount,
                unmount_on_exit,
                disabled_keys,
                reorderable,
            },
        )
}

