530	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context) {
531	        let mut selected = if let Some(value) = &props.selected {
532	            Bindable::controlled(value.clone())
533	        } else {
534	            Bindable::uncontrolled(props.default_selected.clone())
535	        };
536	
537	        let expanded = if let Some(value) = &props.expanded {
538	            Bindable::controlled(value.clone())
539	        } else {
540	            // Honor branches the collection marks expanded via
541	            // `TreeItemConfig::default_expanded`, unioned with the
542	            // component-level `default_expanded` prop, so either source of
543	            // initial expansion works (pit of success).
544	            let mut initial = props
545	                .items
546	                .all_nodes()
547	                .filter(|node| node.is_expanded == Some(true))
548	                .map(|node| node.key.clone())
549	                .collect::<BTreeSet<_>>();
550	
551	            initial.extend(props.default_expanded.iter().cloned());
552	
553	            Bindable::uncontrolled(initial)
554	        };
555	
556	        // Disabled nodes are not selectable: seed the selection machine's
557	        // disabled-key set so `select` rejects them (`selection::State::select`
558	        // is a no-op for disabled keys).
559	        let disabled_keys = props
560	            .items
561	            .all_nodes()
562	            .filter(|node| node.value.as_ref().is_some_and(|item| item.disabled))
563	            .map(|node| node.key.clone())
564	            .collect::<BTreeSet<Key>>();
565	
566	        // `multiple = true` upgrades the effective mode to `Multiple`.
567	        let selection_mode = effective_selection_mode(props);
568	
569	        // Seed the selection state machine from the resolved initial selection,
570	        // normalized for the mode so it stays consistent with the `selected`
571	        // binding and never starts in a mode-invalid shape.
572	        let mut selection_state = selection::State::new(selection_mode, props.selection_behavior)
573	            .with_disabled(disabled_keys);
574	        // Disabled nodes stay focusable and typeahead-reachable (FocusOnly) while
575	        // `select` still rejects them, so they cannot be selected.
576	        selection_state.disabled_behavior = selection::DisabledBehavior::FocusOnly;
577	
578	        // Drop any disabled or unknown key from the resolved initial selection so
579	        // a disabled node can never initialize as selected. Write the sanitized
580	        // set back to the binding too (a no-op for a controlled binding, which
581	        // the parent owns) so the public `ctx.selected` agrees with
582	        // `is_node_selected` and the rendered ARIA state from the first render.
583	        let sanitized = sanitize_selection(
584	            selected.get().clone(),
585	            selection_mode,
586	            &props.items,
587	            &selection_state.disabled_keys,
588	        );
589	        selected.set(sanitized.clone());
590	        selection_state.selected_keys = sanitized;
591	
592	        (
593	            State::Idle,
594	            Context {
595	                items: props.items.clone(),
596	                selected,
597	                selection_state,
598	                expanded,
599	                focused_node: None,
600	                focus_visible: false,
601	                multiple: props.multiple,
602	                selection_mode,
603	                typeahead: typeahead::State::default(),
604	                locale: env.locale.clone(),
605	                messages: messages.clone(),
606	                ids: ComponentIds::from_id(&props.id),
607	                dragging: None,
608	                drop_target: None,
609	            },
610	        )
611	    }
