613	    fn transition(
614	        _state: &State,
615	        event: &Event,
616	        ctx: &Context,
617	        props: &Props,
618	    ) -> Option<TransitionPlan<Self>> {
619	        match event {
620	            // Expand/collapse/toggle only act on a real, enabled, expandable
621	            // branch — never a leaf, a disabled node (interaction is blocked),
622	            // or a stale/unknown key (which would otherwise leave invalid keys
623	            // in the expansion set or mark a leaf `data-ars-expanded`).
624	            Event::ExpandNode(key) => {
625	                if !is_interactive_branch(&ctx.items, key) {
626	                    return None;
627	                }
628	                let mut next = ctx.expanded.get().clone();
629	                next.insert(key.clone());
630	                // Expanding never hides the focused node, so no focus clamp.
631	                expanded_change_plan(ctx, next, false)
632	            }
633	
634	            Event::CollapseNode(key) => {
635	                if !is_interactive_branch(&ctx.items, key) {
636	                    return None;
637	                }
638	                let mut next = ctx.expanded.get().clone();
639	                next.remove(key);
640	                // A collapse may hide the focused node, so re-clamp focus.
641	                expanded_change_plan(ctx, next, true)
642	            }
643	
644	            Event::ToggleNode(key) => {
645	                if !is_interactive_branch(&ctx.items, key) {
646	                    return None;
647	                }
648	                let mut next = ctx.expanded.get().clone();
649	                let collapsing = next.remove(key);
650	                if !collapsing {
651	                    next.insert(key.clone());
652	                }
653	                expanded_change_plan(ctx, next, collapsing)
654	            }
655	
656	            Event::SelectNode(key) => {
657	                // Ignore the event in non-selectable mode or for a stale/unknown
658	                // key, so selection never accumulates keys absent from `items`.
659	                if ctx.selection_mode == selection::Mode::None
660	                    || !ctx.items.get(key).is_some_and(Node::is_focusable)
661	                {
662	                    return None;
663	                }
664	
665	                selection_change_plan(ctx, ctx.selection_state.select(key.clone()))
666	            }
667	
668	            Event::DeselectNode(key) => {
669	                selection_change_plan(ctx, ctx.selection_state.deselect(key))
670	            }
671	
672	            // Pointer / programmatic focus: do not force the keyboard focus
673	            // ring (modality is not keyboard). Only focus a node that is
674	            // currently visible, so the active descendant never dangles.
675	            Event::FocusNode(key) => {
676	                if !visible_keys(ctx).contains(key) {
677	                    return None;
678	                }
679	                Some(focus_plan(key.clone(), false))
680	            }
681	
682	            // When the container gains focus with no active node, initialise it
683	            // to the first selected visible node, else the first visible node —
684	            // so `aria-activedescendant` is populated immediately.
685	            Event::Focus { is_keyboard } => {
686	                let is_keyboard = *is_keyboard;
687	                let initial = if ctx.focused_node.is_some() {
688	                    None
689	                } else {
690	                    initial_active_node(ctx)
691	                };
692	                Some(
693	                    TransitionPlan::to(State::Focused)
694	                        .apply(move |ctx: &mut Context| {
695	                            ctx.focus_visible = is_keyboard;
696	                            if let Some(key) = initial {
697	                                ctx.focused_node = Some(key);
698	                            }
699	                        })
700	                        .with_effect(PendingEffect::named(Effect::ScrollFocusedIntoView)),
701	                )
702	            }
703	
704	            Event::Blur => Some(TransitionPlan::to(State::Idle).apply(|ctx: &mut Context| {
705	                ctx.focus_visible = false;
706	                // Reset typeahead so a refocus within the timeout starts a
707	                // fresh search rather than appending to the old buffer.
708	                ctx.typeahead = typeahead::State::default();
709	            })),
710	
711	            Event::FocusNext => focus_relative(ctx, Direction::Next),
712	
713	            Event::FocusPrev => focus_relative(ctx, Direction::Prev),
714	
715	            Event::FocusFirst => visible_keys(ctx)
716	                .first()
717	                .cloned()
718	                .map(|key| focus_plan(key, true)),
719	
720	            Event::FocusLast => visible_keys(ctx)
721	                .last()
722	                .cloned()
723	                .map(|key| focus_plan(key, true)),
724	
725	            Event::FocusParent => ctx
726	                .focused_node
