            Self::Route(route) => route.as_str(),
        }
    }

    /// Returns `true` when this target is an absolute HTTP(S) URL.
    #[must_use]
    pub fn is_external(&self) -> bool {
        let href = self.href();

        href.starts_with("http://") || href.starts_with("https://")
    }
}

