81	/// Asserts the cross-cutting `NavigationMenu` invariants after any reachable
82	/// state.
83	fn assert_nm_invariants(service: &Service<navigation_menu::Machine>) -> TestCaseResult {
84	    let ctx = service.context();
85	    let api = service.connect(&|_| {});
86	
87	    // Once the adapter has registered the trigger list, the open item is never a
88	    // phantom: `open_item()` only reports a registered trigger, so a stale
89	    // controlled value pointing at an unregistered key cannot open a panel.
90	    // Before registration the gate is intentionally permissive so a
91	    // controlled/default value opens ahead of the first `SetItems` sync (pit of
92	    // success), so the membership check only applies post-registration.
93	    if ctx.items_registered
94	        && let Some(open) = api.open_item()
95	    {
96	        prop_assert!(
97	            ctx.items.contains(open),
98	            "open_item {open:?} is not among the registered triggers"
99	        );
100	    }
101	
102	    // Every registered trigger renders the canonical menuitem ARIA set, and its
103	    // `aria-expanded` agrees with `is_item_open`.
104	    for key in &ctx.items {
105	        let attrs = api.trigger_attrs(key, "content-id");
106	
107	        prop_assert_eq!(
108	            attrs.get(&HtmlAttr::Role),
109	            Some("menuitem"),
110	            "trigger role missing"
111	        );
112	        prop_assert_eq!(
113	            attrs.get(&HtmlAttr::Aria(AriaAttr::HasPopup)),
114	            Some("true"),
115	            "aria-haspopup missing"
116	        );
117	        prop_assert!(attrs.get(&HtmlAttr::TabIndex).is_some(), "tabindex missing");
118	
119	        let expanded = attrs.get(&HtmlAttr::Aria(AriaAttr::Expanded));
120	
121	        let expected = if api.is_item_open(key) {
122	            "true"
123	        } else {
124	            "false"
125	        };
126	
127	        prop_assert_eq!(
128	            expanded,
129	            Some(expected),
130	            "aria-expanded must mirror open state"
131	        );
132	    }
133	
134	    Ok(())
135	}
